description:
Create the `TasksPage` widget and register the `/tasks` route in the TanStack Router.

## TasksPage widget

File: `apps/client/src/layers/widgets/tasks/ui/TasksPage.tsx`

Mirrors the `AgentsPage` widget structure. FSD layer: `widgets/tasks/`.

```typescript
import { TasksList, taskFilterSchema } from '@/layers/features/tasks';
import { Zap } from 'lucide-react';

/**
 * Top-level Tasks page widget.
 *
 * Displays a filterable, sortable list of all tasks across all agents.
 * Accessible via /tasks route.
 */
export function TasksPage() {
  return (
    <div className="flex h-full flex-col">
      <TasksHeader />
      <div className="flex-1 overflow-auto p-4">
        <FilterBar schema={taskFilterSchema} />
        <TasksList />
      </div>
    </div>
  );
}
```

